SELECT service_id, price
FROM company_services
WHERE company_id = 0;

SELECT COUNT(*) AS active_employee_count
FROM employees
WHERE company_id = (SELECT company_id FROM companies WHERE company_name = 'ArborCare Tree Service') AND status = 'active';

SELECT AVG(rating) AS average_rating
FROM employee_services
WHERE employee_id = 0 AND service_id = 0;

SELECT DISTINCT c.customer_name
FROM customers c
WHERE c.customer_id IN (SELECT s.customer_id FROM service_requests s);

SELECT AVG(price) AS average_price, COUNT(*) AS total_services
FROM company_services
WHERE company_id = 1;
